SELECT t.id, t.estado, COALESCE(l.nombre,'') AS ubic FROM ingresos t LEFT JOIN locations l ON l.id=t.ubicacion_id WHERE t.id IN (27122,27509,27637,26773,27935,27998,28053,28074,28075,28079,27369,28147,28159,28228,28229,28234,28221,28261,28273,28251,28308,28310,28318,28320,28393,28442,28446,28476,28478,28479,28480) ORDER BY t.id;
